"use client";

import { cn } from "@workspace/ui/lib/utils";
import type { ReactNode } from "react";

import { useCanvasNode } from "./canvas-node.context";

export function CanvasNodeDragFrame({
  children,
  className,
  dragging = false,
}: {
  children?: ReactNode;
  className?: string;
  dragging?: boolean;
}) {
  if (!dragging) {
    return <>{children}</>;
  }

  return (
    <div
      className={cn("canvas-node-drag-frame inline-flex rounded-lg", className)}
      data-dragging="true"
      data-slot="canvas-node-drag-frame"
    >
      {children}
    </div>
  );
}

export function CanvasNodeDragStateFrame({
  children,
  className,
}: {
  children?: ReactNode;
  className?: string;
}) {
  const {
    state: { interaction },
  } = useCanvasNode();

  return (
    <CanvasNodeDragFrame className={className} dragging={interaction?.dragging}>
      {children}
    </CanvasNodeDragFrame>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";

import type {
  CanvasNodeStatus as CanvasNodeStatusData,
  CanvasNodeStatusTone,
} from "./canvas-node.types";

interface StatusVisual {
  breathing: boolean;
  dotClassName: string;
  pillClassName: string;
}

const GREEN: StatusVisual = {
  breathing: true,
  dotClassName: "bg-green-500",
  pillClassName: "bg-green-500/30 text-zinc-50",
};
const BLUE: StatusVisual = {
  breathing: true,
  dotClassName: "bg-blue-500",
  pillClassName: "bg-blue-500/30 text-zinc-50",
};
const YELLOW: StatusVisual = {
  breathing: true,
  dotClassName: "bg-yellow-500",
  pillClassName: "bg-yellow-500/30 text-zinc-50",
};
const GRAY_BREATHING: StatusVisual = {
  breathing: true,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
};
const GRAY_STATIC: StatusVisual = {
  breathing: false,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
};
const RED: StatusVisual = {
  breathing: true,
  dotClassName: "bg-red-500",
  pillClassName: "bg-red-500/30 text-zinc-50",
};

export function normalizeCanvasNodeStatus(
  input: string | undefined
): CanvasNodeStatusTone {
  const normalized = input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");

  switch (normalized) {
    case "accessible":
    case "available":
    case "bound":
    case "complete":
    case "ready":
    case "running":
    case "succeeded":
      return normalized;
    case "binding":
    case "creating":
    case "pending":
    case "progressing":
      return normalized;
    case "deleting":
    case "stopping":
      return normalized;
    case "shutdown":
    case "stopped":
      return normalized;
    case "degraded":
    case "error":
    case "failed":
    case "inaccessible":
    case "unhealthy":
      return normalized;
    default:
      return "unknown";
  }
}

function getStatusVisual(tone: CanvasNodeStatusTone): StatusVisual {
  switch (tone) {
    case "accessible":
    case "available":
    case "bound":
    case "complete":
    case "ready":
    case "running":
    case "succeeded":
      return GREEN;
    case "binding":
    case "creating":
    case "pending":
    case "progressing":
      return BLUE;
    case "deleting":
      return YELLOW;
    case "stopping":
      return GRAY_BREATHING;
    case "degraded":
    case "error":
    case "failed":
    case "inaccessible":
    case "unhealthy":
      return RED;
    case "shutdown":
    case "stopped":
    case "unknown":
      return GRAY_STATIC;
    default:
      return GRAY_STATIC;
  }
}

function resolveTone(status: CanvasNodeStatusData | undefined) {
  return status?.tone ?? normalizeCanvasNodeStatus(status?.label);
}

export function CanvasNodeStatusDot({
  className,
  size = "default",
  status,
}: {
  className?: string;
  size?: "collapsed" | "default" | "small";
  status?: CanvasNodeStatusData;
}) {
  const visual = getStatusVisual(resolveTone(status));
  const dotSize = size === "default" ? "size-3" : "size-2";
  const pingSize = size === "default" ? "size-2.5" : "size-2";

  return (
    <span
      aria-hidden
      className={cn(
        "relative flex shrink-0 items-center justify-center rounded-full",
        size === "default" ? "size-4" : "size-3.5",
        className
      )}
    >
      {visual.breathing ? (
        <span
          className={cn(
            "absolute animate-ping rounded-full opacity-75",
            pingSize,
            visual.dotClassName
          )}
        />
      ) : null}
      <span
        className={cn("relative rounded-full", dotSize, visual.dotClassName)}
      />
    </span>
  );
}

export function CanvasNodeStatusPill({
  className,
  status,
}: {
  className?: string;
  status?: CanvasNodeStatusData;
}) {
  const statusLabel = status?.label?.trim() || "Unknown";
  const visual = getStatusVisual(resolveTone(status));

  return (
    <span
      className={cn(
        "flex h-5 shrink-0 items-center gap-2.5 rounded-full py-0.5 pr-1 pl-2.5 font-normal text-xs leading-none",
        visual.pillClassName,
        className
      )}
    >
      <span className="truncate">{statusLabel}</span>
      <CanvasNodeStatusDot size="small" status={status} />
    </span>
  );
}

export function CanvasNodeStatus({
  className,
  status,
}: {
  className?: string;
  status: CanvasNodeStatusData;
}) {
  return (
    <span className={cn("canvas-node-status min-w-0 shrink-0", className)}>
      <CanvasNodeStatusPill
        className="canvas-node-status-pill max-w-28"
        status={status}
      />
      <CanvasNodeStatusDot
        className="canvas-node-status-dot"
        size="collapsed"
        status={status}
      />
    </span>
  );
}

.canvas-node-hover-surface {
  --canvas-node-surface-underlay: transparent;
}

.canvas-node-hover-surface:hover,
.canvas-node-frame:hover .canvas-node-hover-surface,
.canvas-node-frame[data-hover-intent] .canvas-node-hover-surface,
.canvas-node-drag-frame[data-dragging="true"] .canvas-node-hover-surface,
.canvas-node-frame[data-selected] .canvas-node-hover-surface {
  --canvas-node-surface-underlay: var(
    --canvas-node-surface-interaction-underlay
  );
  box-shadow:
    -1px -1px 6px 0 rgb(255 255 255 / 4.5%),
    1px 1px 6px 0 rgb(255 255 255 / 4.5%);
}

.canvas-node-frame {
  --canvas-node-surface-base: rgb(255 255 255 / 4.5%);
  --canvas-node-surface-interaction-underlay: rgb(9 9 11 / 20%);
  --canvas-node-surface-underlay: transparent;
  --canvas-node-card-width-collapsed: calc(var(--spacing) * 40);
  --canvas-node-card-height-collapsed: calc(var(--spacing) * 10);
  --canvas-node-card-width-expanded: calc(var(--spacing) * 66.75);
  --canvas-node-card-height-expanded: calc(var(--spacing) * 55);
  --canvas-node-connection-size: calc(var(--spacing) * 5);
  --canvas-node-connection-gap: calc(var(--spacing) * 1.5);
  --canvas-node-expand-size: calc(var(--spacing) * 8);
  --canvas-node-expand-gap: calc(var(--spacing) * 2);
  --canvas-node-frame-gutter: calc(
    var(--canvas-node-connection-size) +
    var(--canvas-node-connection-gap)
  );
  width: var(--canvas-node-card-width-collapsed);
  height: var(--canvas-node-card-height-collapsed);
  transition:
    width 180ms cubic-bezier(0.16, 1, 0.3, 1),
    height 180ms cubic-bezier(0.16, 1, 0.3, 1);
}

.canvas-node-frame[data-state="expanded"] {
  width: var(--canvas-node-card-width-expanded);
  height: var(--canvas-node-card-height-expanded);
}

.canvas-node-surface {
  --canvas-node-card-width-collapsed: calc(var(--spacing) * 40);
  --canvas-node-card-height-collapsed: calc(var(--spacing) * 10);
  --canvas-node-card-width-expanded: calc(var(--spacing) * 66.75);
  --canvas-node-card-height-expanded: calc(var(--spacing) * 55);
  width: var(--canvas-node-card-width-collapsed);
  min-height: var(--canvas-node-card-height-collapsed);
  background:
    linear-gradient(
      90deg,
      var(--canvas-node-surface-base) 0%,
      var(--canvas-node-surface-base) 100%
    ),
    linear-gradient(
      90deg,
      var(--canvas-node-surface-underlay) 0%,
      var(--canvas-node-surface-underlay) 100%
    );
  transition:
    width 180ms cubic-bezier(0.16, 1, 0.3, 1),
    min-height 180ms cubic-bezier(0.16, 1, 0.3, 1),
    background 150ms ease,
    box-shadow 150ms ease;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-surface {
  width: var(--canvas-node-card-width-expanded);
  min-height: var(--canvas-node-card-height-expanded);
}

.canvas-node-header {
  min-height: var(--canvas-node-card-height-collapsed);
  padding: calc(var(--spacing) * 2.5);
}

.canvas-node-frame[data-state="expanded"] .canvas-node-header {
  align-items: flex-start;
  min-height: calc(var(--spacing) * 11.5);
}

.canvas-node-header-content {
  display: flex;
  flex-direction: column;
}

.canvas-node-header-secondary {
  display: none;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-header-secondary {
  display: block;
}

.canvas-node-status-pill {
  display: none;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-status-pill {
  display: flex;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-status-dot {
  display: none;
}

.canvas-node-body {
  display: grid;
  grid-template-rows: 0fr;
  opacity: 0;
  transition:
    grid-template-rows 180ms cubic-bezier(0.16, 1, 0.3, 1),
    opacity 120ms ease;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-body {
  grid-template-rows: 1fr;
  opacity: 1;
  transition-delay: 40ms;
}

.canvas-node-body-clip {
  min-height: 0;
  padding: 0 calc(var(--spacing) * 2.5);
  overflow: hidden;
}

.canvas-node-frame[data-state="expanded"] .canvas-node-body-clip {
  padding-bottom: calc(var(--spacing) * 2.5);
}

.canvas-node-connection-button {
  pointer-events: none;
  opacity: 0;
  transition: opacity 150ms ease;
}

.canvas-node-frame[data-state="expanded"][data-hover-intent]
  .canvas-node-connection-button,
.canvas-node-frame[data-state="expanded"][data-selected]
  .canvas-node-connection-button {
  pointer-events: auto;
  opacity: 1;
}

.canvas-node-connection-button[data-side="top"] {
  top: calc(-1 * var(--canvas-node-frame-gutter));
  left: 50%;
  transform: translateX(-50%);
}

.canvas-node-connection-button[data-side="right"] {
  top: 50%;
  right: calc(-1 * var(--canvas-node-frame-gutter));
  transform: translateY(-50%);
}

.canvas-node-connection-button[data-side="bottom"] {
  bottom: calc(-1 * var(--canvas-node-frame-gutter));
  left: 50%;
  transform: translateX(-50%);
}

.canvas-node-connection-button[data-side="left"] {
  top: 50%;
  left: calc(-1 * var(--canvas-node-frame-gutter));
  transform: translateY(-50%);
}

.canvas-node-drag-frame {
  position: relative;
}

.canvas-node-drag-frame::before {
  --canvas-node-drag-stroke: rgb(255 255 255 / 15%);
  --canvas-node-drag-stroke-clear: rgb(255 255 255 / 0%);
  position: absolute;
  inset: -4px;
  padding: 1px;
  pointer-events: none;
  content: "";
  background:
    linear-gradient(
      135deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    ),
    linear-gradient(
      315deg,
      var(--canvas-node-drag-stroke) 0%,
      var(--canvas-node-drag-stroke-clear) 18%
    );
  border-radius: inherit;
  -webkit-mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
}

.canvas-node-expand-button {
  --canvas-node-expand-underlay: transparent;
  position: absolute;
  top: 0;
  left: calc(
    50% +
    var(--canvas-node-card-width-expanded) /
    2 +
    var(--canvas-node-expand-gap)
  );
  width: var(--canvas-node-expand-size);
  height: var(--canvas-node-expand-size);
  color: rgb(161 161 170);
  pointer-events: none;
  cursor: pointer;
  background:
    linear-gradient(
      90deg,
      var(--canvas-node-surface-base) 0%,
      var(--canvas-node-surface-base) 100%
    ),
    linear-gradient(
      90deg,
      var(--canvas-node-expand-underlay) 0%,
      var(--canvas-node-expand-underlay) 100%
    );
  opacity: 0;
  transition:
    opacity 150ms ease,
    background 150ms ease,
    color 150ms ease;
}

.canvas-node-expand-button::before {
  position: absolute;
  top: 0;
  bottom: 0;
  left: calc(-1 * var(--canvas-node-expand-gap));
  width: var(--canvas-node-expand-gap);
  content: "";
}

.canvas-node-frame[data-state="expanded"]:hover .canvas-node-expand-button,
.canvas-node-frame[data-state="expanded"][data-hover-intent]
  .canvas-node-expand-button,
.canvas-node-frame[data-state="expanded"][data-selected]
  .canvas-node-expand-button {
  pointer-events: auto;
  opacity: 1;
}

.canvas-node-expand-button:hover {
  --canvas-node-expand-underlay: var(
    --canvas-node-surface-interaction-underlay
  );
}

